class MainActivity : ComponentActivity() { override fun onCreate(savedInstanceState: Bundle?) { super.onCreate(savedInstanceState) enableEdgeToEdge()
// Initialize Database and Repository val database = ExpenseDatabase.getDatabase(this) val expenseDao = database.expenseDao() val repository = ExpenseRepository(expenseDao) val viewModelFactory = ExpenseViewModelFactory(repository) val viewModel = ViewModelProvider(this, viewModelFactory).get(ExpenseViewModel::class.java)
