package com.ramzi.personalexpensemanagment.data
import androidx.room.Entity import androidx.room.PrimaryKey import java.time.LocalDate
@Entity(tableName = "expenses") data class Expense( @PrimaryKey(autoGenerate = true) val id: Int = 0, val title: String, val amount: Double, val category: String, val date: Long, // Stored as timestamp for easier database handling val description: String = "" )

package com.ramzi.personalexpensemanagment.data

import androidx.room.Dao
import androidx.room.Delete
import androidx.room.Insert
import androidx.room.Query
import androidx.room.Update
import kotlinx.coroutines.flow.Flow

@Dao
interface ExpenseDao {
    @Insert
    suspend fun insertExpense(expense: Expense)

    @Update
    suspend fun updateExpense(expense: Expense)

    @Delete
    suspend fun deleteExpense(expense: Expense)

    @Query("SELECT * FROM expenses ORDER BY date DESC")
    fun getAllExpenses(): Flow<List<Expense>>

    @Query("SELECT * FROM expenses WHERE category = :category ORDER BY date DESC")
    fun getExpensesByCategory(category: String): Flow<List<Expense>>

    @Query("SELECT * FROM expenses WHERE date BETWEEN :startDate AND :endDate ORDER BY date DESC")
    fun getExpensesByDateRange(startDate: Long, endDate: Long): Flow<List<Expense>>

    @Query("SELECT SUM(amount) FROM expenses")
    fun getTotalSpending(): Flow<Double?>

    @Query("SELECT SUM(amount) FROM expenses WHERE category = :category")
    fun getCategoryTotal(category: String): Flow<Double?>

    @Query("SELECT DISTINCT category FROM expenses")
    fun getAllCategories(): Flow<List<String>>
}

package com.ramzi.personalexpensemanagment.data

import android.content.Context
import androidx.room.Database
import androidx.room.Room
import androidx.room.RoomDatabase

@Database(entities = [Expense::class], version = 1, exportSchema = false)
abstract class ExpenseDatabase : RoomDatabase() {
    abstract fun expenseDao(): ExpenseDao

    companion object {
        @Volatile
        private var INSTANCE: ExpenseDatabase? = null

        fun getDatabase(context: Context): ExpenseDatabase {
            return INSTANCE ?: synchronized(this) {
                val instance = Room.databaseBuilder(
                    context.applicationContext,
                    ExpenseDatabase::class.java,
                    "expense_database"
                ).build()
                INSTANCE = instance
                instance
            }
        }
    }
}

package com.ramzi.personalexpensemanagment.data

import kotlinx.coroutines.flow.Flow

class ExpenseRepository(private val expenseDao: ExpenseDao) {

    suspend fun insertExpense(expense: Expense) {
        expenseDao.insertExpense(expense)
    }

    suspend fun updateExpense(expense: Expense) {
        expenseDao.updateExpense(expense)
    }

    suspend fun deleteExpense(expense: Expense) {
        expenseDao.deleteExpense(expense)
    }

    fun getAllExpenses(): Flow<List<Expense>> {
        return expenseDao.getAllExpenses()
    }

    fun getExpensesByCategory(category: String): Flow<List<Expense>> {
        return expenseDao.getExpensesByCategory(category)
    }

    fun getExpensesByDateRange(startDate: Long, endDate: Long): Flow<List<Expense>> {
        return expenseDao.getExpensesByDateRange(startDate, endDate)
    }

    fun getTotalSpending(): Flow<Double> {
        return expenseDao.getTotalSpending()
    }

    fun getCategoryTotal(category: String): Flow<Double> {
        return expenseDao.getCategoryTotal(category)
    }

    fun getAllCategories(): Flow<List<String>> {
        return expenseDao.getAllCategories()
    }
}

package com.ramzi.personalexpensemanagment.ui.navigation

import androidx.compose.runtime.Composable
import androidx.navigation.NavHostController
import androidx.navigation.compose.NavHost
import androidx.navigation.compose.composable
import com.ramzi.personalexpensemanagment.ui.screens.AddExpenseScreen
import com.ramzi.personalexpensemanagment.ui.screens.ExpenseListScreen
import com.ramzi.personalexpensemanagment.ui.screens.HomeScreen
import com.ramzi.personalexpensemanagment.ui.screens.StatsScreen
import com.ramzi.personalexpensemanagment.ui.viewmodel.ExpenseViewModel

@Composable
fun AppNavigation(
    navController: NavHostController,
    viewModel: ExpenseViewModel
) {
    NavHost(
        navController = navController,
        startDestination = Screen.Home.route
    ) {
        composable(Screen.Home.route) {
            HomeScreen(
                viewModel = viewModel,
                onAddExpenseClick = { navController.navigate(Screen.AddExpense.route) },
                onViewExpensesClick = { navController.navigate(Screen.ExpenseList.route) },
                onViewStatsClick = { navController.navigate(Screen.Stats.route) }
            )
        }

        composable(Screen.AddExpense.route) {
            AddExpenseScreen(
                viewModel = viewModel,
                onNavigateBack = { navController.popBackStack() }
            )
        }

        composable(Screen.ExpenseList.route) {
            ExpenseListScreen(
                viewModel = viewModel,
                onNavigateBack = { navController.popBackStack() }
            )
        }

        composable(Screen.Stats.route) {
            StatsScreen(
                viewModel = viewModel,
                onNavigateBack = { navController.popBackStack() }
            )
        }
    }
}

