val categoryColors = mapOf(
    "Food" to Color(0xFFFF6B6B),
    "Transport" to Color(0xFF4ECDC4),
    "Entertainment" to Color(0xFFFFE66D),
    "Education" to Color(0xFF95E1D3),
    "Health" to Color(0xFFC7CEEA),
    "Other" to Color(0xFFB0BEC5)
)

@OptIn(ExperimentalMaterial3Api::class)
@Composable
fun StatsScreen(
    viewModel: ExpenseViewModel,
    onNavigateBack: () -> Unit
) {
    val totalSpending by viewModel.totalSpending.collectAsState()
    val categories by viewModel.categories.collectAsState()
    val categoryTotals by viewModel.categoryTotals.collectAsState()

    Scaffold(
        topBar = {
            TopAppBar(
                title = { Text("Statistics & Dashboard") },
                navigationIcon = {
                    IconButton(onClick = onNavigateBack) {
                        Icon(Icons.Default.ArrowBack, contentDescription = "Back")
                    }
                }
            )
        }
    ) { innerPadding ->
        Column(
            modifier = Modifier
                .fillMaxSize()
                .padding(innerPadding)
                .verticalScroll(rememberScrollState())
                .padding(16.dp),
            verticalArrangement = Arrangement.spacedBy(16.dp)
        ) {
            // Total Spending Card
            Card(
                modifier = Modifier.fillMaxWidth(),
                elevation = CardDefaults.cardElevation(defaultElevation = 4.dp),
                colors = CardDefaults.cardColors(
                    containerColor = MaterialTheme.colorScheme.primaryContainer
                )
            ) {
                Column(
                    modifier = Modifier
                        .fillMaxWidth()
                        .padding(20.dp),
                    horizontalAlignment = Alignment.CenterHorizontally
                ) {
                    Text(
                        text = "Total Spending",
                        fontSize = 16.sp,
                        color = MaterialTheme.colorScheme.onPrimaryContainer
                    )
                    Spacer(modifier = Modifier.height(8.dp))
                    Text(
                        text = "%.2f DA".format(totalSpending),
                        fontSize = 32.sp,
                        fontWeight = FontWeight.Bold,
                        color = MaterialTheme.colorScheme.onPrimaryContainer
                    )
                }
            }

            // Category Breakdown Title
            Text(
                text = "Spending by Category",
                fontSize = 18.sp,
                fontWeight = FontWeight.Bold
            )

            // Category Cards
            if (categories.isEmpty()) {
                Text(
                    text = "No spending data yet",
                    modifier = Modifier.fillMaxWidth(),
                    fontSize = 14.sp
                )
            } else {
                categories.forEach { category ->
                    val amount = categoryTotals[category] ?: 0.0
                    val percentage = if (totalSpending > 0) {
                        (amount / totalSpending * 100)
                    } else {
                        0.0
                    }

                    CategoryCard(
                        category = category,
                        amount = amount,
                        percentage = percentage,
                        color = categoryColors[category] ?: Color.Gray
                    )
                }
            }

            // Budget Warning Section (Example)
            Spacer(modifier = Modifier.height(16.dp))
            Card(
                modifier = Modifier.fillMaxWidth(),
                elevation = CardDefaults.cardElevation(defaultElevation = 2.dp),
                colors = CardDefaults.cardColors(
                    containerColor = Color(0xFFFFF3E0)
                )
            ) {
                Column(
                    modifier = Modifier.padding(16.dp)
                ) {
                    Text(
                        text = " Tip",
                        fontWeight = FontWeight.Bold,
                        fontSize = 14.sp
                    )
                    Text(
                        text = "Track your spending by category to identify patterns and save money!",
                        fontSize = 12.sp,
                        modifier = Modifier.padding(top = 8.dp)
                    )
                }
            }
        }
    }
}

@Composable
fun CategoryCard(
    category: String,
    amount: Double,
    percentage: Double,
    color: Color
) {
    Card(
        modifier = Modifier.fillMaxWidth(),
        elevation = CardDefaults.cardElevation(defaultElevation = 2.dp)
    ) {
        Column(
            modifier = Modifier
                .fillMaxWidth()
                .padding(12.dp)
        ) {
            Row(
                modifier = Modifier.fillMaxWidth(),
                horizontalArrangement = Arrangement.SpaceBetween,
                verticalAlignment = Alignment.CenterVertically
            ) {
                Row(
                    verticalAlignment = Alignment.CenterVertically,
                    modifier = Modifier.weight(1f)
                ) {
                    Box(
                        modifier = Modifier
                            .size(12.dp)
                            .clip(CircleShape)
                            .background(color)
                    )
                    Text(
                        text = category,
                        fontWeight = FontWeight.SemiBold,
                        fontSize = 14.sp,
                        modifier = Modifier.padding(start = 8.dp)
                    )
                }
                Text(
                    text = "%.2f DA".format(amount),
                    fontWeight = FontWeight.Bold,
                    fontSize = 14.sp
                )
            }

            // Progress Bar
            Box(
                modifier = Modifier
                    .fillMaxWidth()
                    .height(8.dp)
                    .padding(top = 8.dp)
                    .background(Color.LightGray)
                    .clip(shape = androidx.compose.foundation.shape.RoundedCornerShape(4.dp))
            ) {
                Box(
                    modifier = Modifier
                        .fillMaxWidth(fraction = (percentage / 100).toFloat().coerceIn(0f, 1f))
                        .height(8.dp)
                        .background(color)
                        .clip(shape = androidx.compose.foundation.shape.RoundedCornerShape(4.dp))
                )
            }

            Text(
                text = "%.1f%%".format(percentage),
                fontSize = 12.sp,
                modifier = Modifier.padding(top = 4.dp)
            )
        }
    }
}

package com.ramzi.personalexpensemanagment.ui.viewmodel

import androidx.lifecycle.ViewModel
import androidx.lifecycle.ViewModelProvider
import androidx.lifecycle.viewModelScope
import com.ramzi.personalexpensemanagment.data.Expense
import com.ramzi.personalexpensemanagment.data.ExpenseRepository
import kotlinx.coroutines.flow.MutableStateFlow
import kotlinx.coroutines.flow.StateFlow
import kotlinx.coroutines.flow.asStateFlow
import kotlinx.coroutines.launch

class ExpenseViewModel(private val repository: ExpenseRepository) : ViewModel() {

    private val _allExpenses = MutableStateFlow<List<Expense>>(emptyList())
    val allExpenses: StateFlow<List<Expense>> = _allExpenses.asStateFlow()

    private val _totalSpending = MutableStateFlow(0.0)
    val totalSpending: StateFlow<Double> = _totalSpending.asStateFlow()

    private val _categories = MutableStateFlow<List<String>>(emptyList())
    val categories: StateFlow<List<String>> = _categories.asStateFlow()

    private val _categoryTotals = MutableStateFlow<Map<String, Double>>(emptyMap())
    val categoryTotals: StateFlow<Map<String, Double>> = _categoryTotals.asStateFlow()

    init {
        loadAllExpenses()
        loadTotalSpending()
        loadCategories()
    }

    private fun loadAllExpenses() {
        viewModelScope.launch {
            repository.getAllExpenses().collect { expenses ->
                _allExpenses.value = expenses
            }
        }
    }

    private fun loadTotalSpending() {
        viewModelScope.launch {
            repository.getTotalSpending().collect { total ->
                _totalSpending.value = total ?: 0.0
            }
        }
    }

    private fun loadCategories() {
        viewModelScope.launch {
            repository.getAllCategories().collect { cats ->
                _categories.value = cats
                // Load totals for each category
                loadCategoryTotals(cats)
            }
        }
    }

    private fun loadCategoryTotals(categories: List<String>) {
        viewModelScope.launch {
            val totals = mutableMapOf<String, Double>()
            for (category in categories) {
                repository.getCategoryTotal(category).collect { total ->
                    totals[category] = total ?: 0.0
                    _categoryTotals.value = totals.toMap()
                }
            }
        }
    }

    fun addExpense(title: String, amount: Double, category: String, date: Long, description: String) {
        viewModelScope.launch {
            val expense = Expense(
                title = title,
                amount = amount,
                category = category,
                date = date,
                description = description
            )
            repository.insertExpense(expense)
        }
    }

    fun deleteExpense(expense: Expense) {
        viewModelScope.launch {
            repository.deleteExpense(expense)
        }
    }

    fun updateExpense(expense: Expense) {
        viewModelScope.launch {
            repository.updateExpense(expense)
        }
    }

    fun getExpensesByCategory(category: String) {
        viewModelScope.launch {
            repository.getExpensesByCategory(category).collect { expenses ->
                _allExpenses.value = expenses
            }
        }
    }
}

class ExpenseViewModelFactory(private val repository: ExpenseRepository) : ViewModelProvider.Factory {
    override fun <T : ViewModel> create(modelClass: Class<T>): T {
        if (modelClass.isAssignableFrom(ExpenseViewModel::class.java)) {
            @Suppress("UNCHECKED_CAST")
            return ExpenseViewModel(repository) as T
        }
        throw IllegalArgumentException("Unknown ViewModel class")
    }
}

